    "CategoryId" integer NOT NULL,
    CONSTRAINT "PK_SubCategory" PRIMARY KEY ("SubCategoryId"),
    CONSTRAINT "FK_SubCategory_Category_CategoryId" FOREIGN KEY ("CategoryId") REFERENCES "Category" ("CategoryId") ON DELETE CASCADE
